{
  "name": "@openai/codex-plugin-cc",
  "version": "1.0.6",
  "private": true,
  "type": "module",
  "description": "Use Codex from Claude Code to review code or delegate tasks.",
  "license": "Apache-2.0",
  "engines": {
    "node": ">=18.18.0"
  },
  "scripts": {
    "bump-version": "node scripts/bump-version.mjs",
    "check-version": "node scripts/bump-version.mjs --check",
    "prebuild": "mkdir -p plugins/codex/.generated/app-server-types && codex app-server generate-ts --out plugins/codex/.generated/app-server-types",
    "build": "tsc -p tsconfig.app-server.json",
    "test": "node --test tests/*.test.mjs"
  },
  "devDependencies": {
    "@types/node": "^25.5.0",
    "typescript": "^6.0.2"
  }
}

{
	"name": "linkswift",
	"version": "1.1.3.1",
	"description": "一个基于 JavaScript 的网盘文件下载地址获取工具",
	"main": "eslint.config.js",
	"scripts": {
		"test": "echo \"Error: no test specified\" && exit 1",
		"check": "npx eslint . --fix"
	},
	"repository": {
		"type": "git",
		"url": "git+https://github.com/hmjz100/LinkSwift.git"
	},
	"keywords": [
		"linkswift",
		"link",
		"swift",
		"download",
		"file",
		"address",
		"get"
	],
	"author": "hmjz100",
	"license": "AGPL-3.0",
	"type": "commonjs",
	"bugs": {
		"url": "https://github.com/hmjz100/LinkSwift/issues"
	},
	"homepage": "https://github.com/hmjz100/LinkSwift#readme",
	"devDependencies": {
		"@eslint/js": "^10.0.1",
		"eslint": "^10.6.0"
	},
	"dependencies": {
		"@eslint/js": "^10.0.1",
		"eslint": "^10.6.0"
	}
}
